            // Update ST_UP using DP_UP[j] at value nums[j]
            ST_UP.update(nums[j], DP_UP[j]);

            // Update ST_DOWN using DP_DOWN[j] at value nums[j]
            ST_DOWN.update(nums[j], DP_DOWN[j]);
        }

        // Step 2: Calculate DP_UP[i] (Sequence ends: ... < nums[i])
        // We need max DP_DOWN[j] where j <= i-k and nums[j] < nums[i].
        // Query ST_DOWN in range [1, V_i - 1]
        let max_prev_score_up = ST_DOWN.query(1, V_i - 1);

        // Length 1 sequence: score is V_i. If max_prev_score_up is 0, we take V_i + 0.
        DP_UP[i] = V_i + max_prev_score_up;


        // Step 3: Calculate DP_DOWN[i] (Sequence ends: ... > nums[i])
        // We need max DP_UP[j] where j <= i-k and nums[j] > nums[i].
        // Query ST_UP in range [V_i + 1, V_MAX]
        let max_prev_score_down = ST_UP.query(V_i + 1, V_MAX);

        // Length 1 sequence: score is V_i.
        DP_DOWN[i] = V_i + max_prev_score_down;

        // Step 4: Update overall max score
        max_score = Math.max(max_score, DP_UP[i], DP_DOWN[i]);
    }

    return max_score;
}
